import axios from 'axios';

const BASE_URL = 'http://localhost:5000/api/';
const TOKEN = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6IjYzMzU4NDFkYjg0ZDQ1NmQyMTZmMDAzZSIsImlzQWRtaW4iOnRydWUsImlhdCI6MTY2NDk2MDgwMSwiZXhwIjoxNjY1MjIwMDAxfQ.IVVodcTeSicv0Y0A7L5wn0gDlVfQPA7BlSXca6nL1Ok';

export const publicRequest = axios.create({
    baseURL: BASE_URL
});

export const userRequest = axios.create({
    baseURL: BASE_URL,
    header: {token: `Bearer ${TOKEN}`},
});
